    {
      "n": 3,
      "column": "left",
      "text": "Tschetrdefnits Ruhlenus\nbuhs wiꞥnam liet tam doht/ wiꞥ-\nxam ne buhs wairak peelikt/ ka\nne/ ja tas wehl wairak wiꞥnu\npahr scheim liktu kult/ taws\nBrahlis nejaufs tohp tawas\nAzzis.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Tew ne buhs tam Wehr-\nfcham/ kas to Labbibu min/ to\nBurni apfeet.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Kad Brahti kohpâ dshwo/\nun weens no teem mirst/ un tam\nDehla newaid/ tad ne buhs ta\nMirruscha Seewai kahdam zit-\ntam twescham Wihranu ( par\nSeewu) tapt/ bet ta Wihra\nBrahlis laid pee wiꞥnas ee-cet/\nun winnu par Seewu nem/ un\ndarra wiꞥrai/ kas Wihra Brah-\nkam peenahkahs.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Un to Pirmdsiminufchu/\nfo wiꞥna dsemdehs/ buhs wiꞥ-\nxam jawu nomirruscha Brahta\nWahrdâ likt/ ka wiꞥna Wahrdg\nno Israëka ne tohp isdeldehts.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Bet ja schim Wihranu ne\npatihk fawa Brahta Seewu\nneint/ tad lai wiꞥna Brahta\nSeewa eet appakfch tahm Wahr-\ntim pee teem Wezzajeem/ un tak-\nka : Mans Wihra Brahlis lee-\ndsahs fawam Brahtam Wahrdn\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "zelt eeksch Israëka/ wiꞥsch man\nne grib darriht/ kas Wihra Brah-\nkam peenahkahs.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Tad tai winna Pilstahta\nWezzajee wiꞥnu atzina/ un us\nwiꞥnu runna/ ja tad wiꞥsch pa-\nstahw/ un fakka : Man ne pa-\ntihk wiꞥnu reint.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Tad lai winna Brahta\nSeewa pee wiꞥna eet preekfch to\nWezzaju Azzim/ un winnam\nweenu Kurpi no wiꞥna Kahjas\niswelk/ un winnam Waigâ\nfptauj/ tad laid winna atbild un\nfakka : Ta taps tam Wihran\ndarrihts/ kasfawa Brahta Nam-\nmu ne grib uszelt.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Un winna Wahrdg taps\neekfch Israëta nosaukts tas Bafs-\nKahja Nans.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Kad Wihti weens ar ohtru\nbarrahs/ un ta weena Seewa pee-\neet fawu Wihtu isglahbt no fa-\nwa Kubleja Rohkas/ un fawu\nRohku issteepj/ un winna Kan-\nnunu fagrahbj.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Tad buhs tew wiꞥkai to\nRobku nozirst/ laid tawa Azz ne\nschehlo.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Tew ne buhs diwejadu\nSwarru tawâ Kullê turreht/\nweenu leelu un weenu masu.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Tew ne buhs tawâ Nam-\nmâ diwejadu Puhru turreht/ wee-\nnu leelu un weenu masu.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Laid tew weens pilnigs un\ntafns Swars irr/ laid tew weens\npilnigs un tafns Puhrs irr/ ka\ntu ilgi dshwo wirs tahs Sem-\n"
    }
